      } else {
        ++node_match[leaf].map_refs[2];
        if (node_match[leaf].map_refs[leaf_phase]++ == 0u) {
          count += cut_ref<SwitchActivity>(cuts.cuts(leaf)[node_match[leaf].best_cut[leaf_phase]], ntk.index_to_node(leaf), leaf_phase);
